32	// GenerateChecksum generates a checksum of the YAML file and the files it references.
33	func GenerateChecksum(yamlFilePath string) (string, error) {
34		hash := sha256.New()
35	
36		yamlContent, err := os.ReadFile(yamlFilePath)
37		if err != nil {
38			return "", fmt.Errorf("error reading YAML file: %w", err)
39		}
40		_, err = hash.Write(yamlContent)
41		if err != nil {
42			return "", fmt.Errorf("error writing YAML file to hash: %w", err)
43		}
44	
45		var config ExternalFilesConfig
46		if err := yaml.Unmarshal(yamlContent, &config); err != nil {
47			return "", fmt.Errorf("error unmarshalling YAML: %w", err)
48		}
49	
50		dir := filepath.Dir(yamlFilePath)
51	
52		for i, file := range config.RuleFiles {
53			config.RuleFiles[i] = promconfig.JoinDir(dir, file)
54		}
55		for i, file := range config.ScrapeConfigFiles {
56			config.ScrapeConfigFiles[i] = promconfig.JoinDir(dir, file)
57		}
58	
59		files := map[string][]string{
60			"r": config.RuleFiles,         // "r" for rule files
61			"s": config.ScrapeConfigFiles, // "s" for scrape config files
62		}
63	
64		for _, prefix := range []string{"r", "s"} {
65			for _, pattern := range files[prefix] {
66				matchingFiles, err := filepath.Glob(pattern)
67				if err != nil {
68					return "", fmt.Errorf("error finding files with pattern %q: %w", pattern, err)
69				}
70	
71				for _, file := range matchingFiles {
72					// Write prefix to the hash ("r" or "s") followed by \0, then
73					// the file path.
74					_, err = hash.Write([]byte(prefix + "\x00" + file + "\x00"))
75					if err != nil {
76						return "", fmt.Errorf("error writing %q path to hash: %w", file, err)
77					}
78	
79					// Read and hash the content of the file.
80					content, err := os.ReadFile(file)
81					if err != nil {
82						return "", fmt.Errorf("error reading file %s: %w", file, err)
83					}
84					_, err = hash.Write(append(content, []byte("\x00")...))
85					if err != nil {
86						return "", fmt.Errorf("error writing %q content to hash: %w", file, err)
87					}
88				}
89			}
90		}
91	
92		return hex.EncodeToString(hash.Sum(nil)), nil
93	}
