// Package reloadstatus tracks the outcome of transactional configuration
// reload attempts and persists the most recent outcome to disk so that it
// remains observable across restarts.
package reloadstatus

import (
	"encoding/json"
	"log/slog"
	"os"
	"path/filepath"
	"sync"

	"github.com/prometheus/prometheus/config"
	"github.com/prometheus/prometheus/tsdb/fileutil"
)

// ErrorCategory classifies why a reload attempt did not fully succeed.
type ErrorCategory string

const (
	ErrorCategoryNone     ErrorCategory = "none"
	ErrorCategoryLoad     ErrorCategory = "load_error"
	ErrorCategoryApply    ErrorCategory = "apply_error"
	ErrorCategoryRollback ErrorCategory = "rollback_error"
)

// FileName is the name of the persisted reload status file, stored under the
// TSDB storage directory.
const FileName = "reload_status.json"

// Status is the outcome of the most recent transactional configuration
// reload attempt.
type Status struct {
	LastReloadID         string           `json:"last_reload_id"`
	LastReloadSuccessful bool             `json:"last_reload_successful"`
	ErrorCategory        ErrorCategory    `json:"error_category"`
	ErrorMessage         string           `json:"error_message"`
	AppliedReloaders     []string         `json:"applied_reloaders"`
	RollbackAttempted    bool             `json:"rollback_attempted"`
	RollbackSuccessful   bool             `json:"rollback_successful"`
	FailedReloader       string           `json:"failed_reloader"`
	ReloaderTimingsMs    map[string]int64 `json:"reloader_timings_ms"`
}

func defaultStatus() Status {
	return Status{
		ErrorCategory:     ErrorCategoryNone,
		AppliedReloaders:  []string{},
		ReloaderTimingsMs: map[string]int64{},
	}
}

// Tracker records the outcome of transactional configuration reload
// attempts, persists it to disk, and keeps track of the last known-good
// configuration for rollback purposes.
type Tracker struct {
	logger *slog.Logger
	path   string

	mtx            sync.RWMutex
	status         Status
	lastGoodConfig *config.Config
}

// NewTracker creates a Tracker that persists reload status as JSON under
// storageDir. If a status file already exists, it is loaded so the most
// recent outcome remains observable across restarts. A missing or corrupted
// file is not fatal: the tracker falls back to the zero-value status.
func NewTracker(storageDir string, logger *slog.Logger) *Tracker {
	if logger == nil {
		logger = slog.New(slog.DiscardHandler)
	}
	t := &Tracker{
		logger: logger,
		path:   filepath.Join(storageDir, FileName),
		status: defaultStatus(),
	}
	t.load()
	return t
}

func (t *Tracker) load() {
	data, err := os.ReadFile(t.path)
	if err != nil {
		if !os.IsNotExist(err) {
			t.logger.Warn("Failed to read persisted reload status, ignoring", "file", t.path, "err", err)
		}
		return
	}
	var s Status
	if err := json.Unmarshal(data, &s); err != nil {
		t.logger.Warn("Failed to parse persisted reload status, ignoring", "file", t.path, "err", err)
		return
	}
	if s.AppliedReloaders == nil {
		s.AppliedReloaders = []string{}
	}
	if s.ReloaderTimingsMs == nil {
		s.ReloaderTimingsMs = map[string]int64{}
	}
	t.mtx.Lock()
	t.status = s
	t.mtx.Unlock()
}

// Get returns a copy of the most recently recorded reload status.
func (t *Tracker) Get() Status {
	t.mtx.RLock()
	defer t.mtx.RUnlock()

	s := t.status
	s.AppliedReloaders = append([]string(nil), t.status.AppliedReloaders...)
	timings := make(map[string]int64, len(t.status.ReloaderTimingsMs))
	for k, v := range t.status.ReloaderTimingsMs {
		timings[k] = v
	}
	s.ReloaderTimingsMs = timings
	return s
}

// Record stores the outcome of a reload attempt in memory and persists it to
// disk. Persistence failures are logged but otherwise ignored: the endpoint
// must keep working even if the disk write fails.
func (t *Tracker) Record(s Status) {
	if s.AppliedReloaders == nil {
		s.AppliedReloaders = []string{}
	}
	if s.ReloaderTimingsMs == nil {
		s.ReloaderTimingsMs = map[string]int64{}
	}

	t.mtx.Lock()
	t.status = s
	t.mtx.Unlock()

	t.persist(s)
}

func (t *Tracker) persist(s Status) {
	data, err := json.Marshal(s)
	if err != nil {
		t.logger.Warn("Failed to marshal reload status", "err", err)
		return
	}
	tmp := t.path + ".tmp"
	if err := os.WriteFile(tmp, data, 0o644); err != nil {
		t.logger.Warn("Failed to write reload status file", "file", tmp, "err", err)
		return
	}
	if err := fileutil.Replace(tmp, t.path); err != nil {
		t.logger.Warn("Failed to persist reload status file", "file", t.path, "err", err)
	}
}

// LastGoodConfig returns the last configuration that was successfully
// applied by all reloaders, or nil if none has been recorded yet.
func (t *Tracker) LastGoodConfig() *config.Config {
	t.mtx.RLock()
	defer t.mtx.RUnlock()
	return t.lastGoodConfig
}

