type reloadStatusResponse struct {
	Status string              `json:"status"`
	Data   reloadstatus.Status `json:"data"`
}

func getReloadStatus(t *testing.T, baseURL string) reloadstatus.Status {
	t.Helper()

	resp, err := http.Get(baseURL + "/api/v1/status/reload")
	require.NoError(t, err)
	defer resp.Body.Close()
	require.Equal(t, http.StatusOK, resp.StatusCode)

	body, err := io.ReadAll(resp.Body)
	require.NoError(t, err)

	var out reloadStatusResponse
	require.NoError(t, json.Unmarshal(body, &out))
	require.Equal(t, "success", out.Status)
	return out.Data
}

func postReload(t *testing.T, reloadURL string) int {
	t.Helper()

	resp, err := http.Post(reloadURL, "text/plain", nil)
	require.NoError(t, err)
	defer resp.Body.Close()
	return resp.StatusCode
}

func getConfigYAML(t *testing.T, baseURL string) string {
	t.Helper()

	resp, err := http.Get(baseURL + "/api/v1/status/config")
	require.NoError(t, err)
	defer resp.Body.Close()

	body, err := io.ReadAll(resp.Body)
	require.NoError(t, err)

	out := struct {
		Data struct {
			YAML string `json:"yaml"`
		} `json:"data"`
	}{}
	require.NoError(t, json.Unmarshal(body, &out))
	return out.Data.YAML
}

func waitReady(t *testing.T, baseURL string) {
	t.Helper()
	require.Eventually(t, func() bool {
		resp, err := http.Get(baseURL + "/-/ready")
		if err != nil {
			return false
		}
		defer resp.Body.Close()
		return resp.StatusCode == http.StatusOK
	}, 5*time.Second, 100*time.Millisecond, "Prometheus didn't become ready in time")
}

// TestTransactionalReload_InitialStatus verifies that, before any reload
// attempt, /api/v1/status/reload reports the documented zero-value response
// and does not persist a state file.
func TestTransactionalReload_InitialStatus(t *testing.T) {
	configDir := t.TempDir()
	configFilePath := filepath.Join(configDir, "prometheus.yml")
	require.NoError(t, os.WriteFile(configFilePath, []byte(`
global:
  scrape_interval: 30s
`), 0o644))

	storagePath := t.TempDir()
	port := testutil.RandomUnprivilegedPort(t)
	prom := prometheusCommandWithLogging(t, configFilePath, port,
		"--enable-feature=transactional-reload-config",
		"--web.enable-lifecycle",
		"--storage.tsdb.path="+storagePath,
	)
	require.NoError(t, prom.Start())

	baseURL := "http://localhost:" + strconv.Itoa(port)
	waitReady(t, baseURL)

	status := getReloadStatus(t, baseURL)
	require.Equal(t, "", status.LastReloadID)
